import Foundation
import os.log

struct AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logUserInteraction(userID: String, emailAddress: String) {
        let message = "User \(userID) with email address \(emailAddress) interacted with the app."
        os_log(.info, "%@", message)
    }
    
    func logAPICall(apiName: String, requestPayload: [String: Any], responsePayload: [String: Any]) {
        let message = "User made API call \(apiName) with request payload \(requestPayload) and response payload \(responsePayload)"
        os_log(.info, "%@", message)
    }
    
    func logUserDataChange(userID: String, dataType: String, newValue: Any?) {
        let message = "User \(userID) changed their \(dataType) to \(newValue)"
        os_log(.info, "%@", message)
    }
    
    func logErrorCondition(error: Error, userID: String? = nil) {
        var message = "Encountered error: \(error.localizedDescription)"
        if let userID = userID {
            message += " for user \(userID)"
        }
        os_log(.error, "%@", message)
    }
